1	type Cell = [number, number];
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const result: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      result.push([x + dx, y + dy]);
11	    }
12	  }
13	  return result;
14	};
15	
16	export function nextGeneration(grid: Cell[]): Cell[] {
17	  const liveSet = new Set(grid.map(toKey));
18	  const candidates = new Map<string, Cell>();
19	
20	  for (const cell of grid) {
21	    candidates.set(toKey(cell), cell);
22	    for (const neighbor of neighborsOf(cell)) {
23	      candidates.set(toKey(neighbor), neighbor);
24	    }
25	  }
26	
27	  const result: Cell[] = [];
28	  for (const [key, cell] of candidates) {
29	    const liveNeighborCount = neighborsOf(cell).filter((n) =>
30	      liveSet.has(toKey(n))
31	    ).length;
32	    const isAlive = liveSet.has(key);
33	    if (isAlive && (liveNeighborCount === 2 || liveNeighborCount === 3)) {
34	      result.push(cell);
35	    } else if (!isAlive && liveNeighborCount === 3) {
36	      result.push(cell);
37	    }
38	  }
39	
40	  return result;
41	}
